import { getCookieObj } from '@/utils/common/cookieObj';
import Digicert from '../Digicert/Digicert';
import SitejabberBadge from '../SiteJabber/SitejabberBadge';
import getFooterLinkObject from './FooterLinksData';

const { publicRuntimeConfig } = getConfig();

const FooterLinks = ({ footerType, router, headertype, t, isLighthouse, loadThirdParty }) => {
  const dispatch = useDispatch();
  const { storedata, pageUrls } = useSelector((store) => store.app);
  const customerData = useSelector((store) => store.customer);
  const { menuData, mobileMenuBanner, currentUrl, adminStoreConfig } = useSelector((store) => store.common);
  const customerDataRef = useRef(customerData);
  customerDataRef.current = customerData;

  const dateObj = new Date();
  const cYear = dateObj.getFullYear();

  const renderLinkData = (data, eventtype, eventKey) => {
    return (
      <ul>
        {data &&
          data.map((value, index) => (
            <li key={index}>
              {value.target ? (
                <a
                  href={value.link}
                  target="_blank"
                  onClick={() => {
                    setAdobeFooterLinks(value.name, eventtype, eventKey);
                    click('footer', value.name, 'Home', '');
                  }}
                  {...(value?.rel ? { rel: value?.rel } : {})}
                >
                  {value.name}
                  {value.isNew && (
                    <img
                      src={`${publicRuntimeConfig.CDN_FOR_STATIC_DATA}/static/images/common/refernEarnNew.svg`}
                      alt="new"
                      style={{ marginLeft: '5px', verticalAlign: 'middle' }}
                    />
                  )}
                </a>
              ) : (
                <Link legacyBehavior href={value.link}>
                  <a
                    onClick={() => {
                      setAdobeFooterLinks(value.name, eventtype, eventKey);
                      click('footer', value.name, 'Home', '');
                    }}
                  >
                    {value.name}
                    {value.isNew && (
                      <img
                        src={`${publicRuntimeConfig.CDN_FOR_STATIC_DATA}/static/images/common/refernEarnNew.svg`}
                        alt="new"
                        style={{ marginLeft: '5px', verticalAlign: 'middle' }}
                      />
                    )}
                  </a>
                </Link>
              )}
            </li>
          ))}
      </ul>
    );
  };

  const renderPenalGroup = () => {
    const urlsData = getFooterLinkObject(storedata, pageUrls);
    const isDesktop = storedata.deviceType >= 2;
    return (
      <Panelstyled className="footerLinkMain">
        <PanelGroup id="accordion-example" allOpen={isDesktop}>
          <Panel defaultOpen={isDesktop} eventKey="1" className="contactDetailsBox" title={<h6>{'Get In Touch​'}</h6>}>
            <div className="contactInfoBox">
              <Link legacyBehavior href={t('common:telNumber')}>
                <a
                  onClick={() => {
                    dataLayerPush('contact', 'callus_footer', 'Home', '', 'contact_us');
                    setAdobeFooterLinks('Call Us', 'adb_footer_get_in_touch_links', 'getIntouch');
                  }}
                >
                  <span className="footerSprite phone" />
                  <p>
                    {t('common:callUsNumber')}
                    <span>{' Need to talk? We’re here 24x7.'}</span>
                  </p>
                </a>
              </Link>
            </div>
            <div className="contactInfoBox">
              <Link legacyBehavior href={urlsData.panel1[0].link}>
                <a
                  onClick={() => {
                    dataLayerPush('contact', 'emailus', 'Home', '', 'contact_us');
                    setAdobeFooterLinks(urlsData?.panel1?.[0]?.name, 'adb_footer_get_in_touch_links', 'getIntouch');
                  }}
                >
                  <span className="footerSprite email" />
                  <p>
                    {urlsData.panel1[0].name}
                    <span>{'For your questions, we’re just an email away.'}</span>
                  </p>
                </a>
              </Link>
            </div>
            {
              <div className="contactInfoBox m-bottom-0">
                <Link legacyBehavior href={urlsData.panel1[1].link}>
                  <a
                    onClick={() => {
                      setAdobeFooterLinks('Need Help?', 'adb_footer_get_in_touch_links', 'getIntouch');
                    }}
                  >
                    <span className="footerSprite help" />
                    <p>
                      Need help?
                      <span>{urlsData.panel1[1].name}</span>
                    </p>
                  </a>
                </Link>
              </div>
            }
          </Panel>
          {
            <Panel defaultOpen={isDesktop} eventKey="2" className="shortLinkBox categoryBox" title={<h6>Category</h6>}>
              {renderLinkData(urlsData.panel5, 'adb_footer_category_links', 'category')}
            </Panel>
          }

          <Panel defaultOpen={isDesktop} eventKey="3" className="shortLinkBox informationBox" title={<h6>{'Information'}</h6>}>
            {renderLinkData(urlsData.panel2, 'adb_footer_information_links', 'information')}
          </Panel>
          <Panel defaultOpen={isDesktop} eventKey="4" className="shortLinkBox customerSerivceBox" title={<h6>{'Customer Service'}</h6>}>
            {renderLinkData(urlsData.panel3, 'adb_footer_customer_serivce_links', 'customerSerivce')}
          </Panel>
          {
            <Panel defaultOpen={isDesktop} eventKey="5" className="shortLinkBox helpStationBox" title={<h6>Help Station</h6>}>
              {renderLinkData(urlsData.panel4, 'adb_footer_help_station_links', 'helpStation')}
            </Panel>
          }
          <Panel defaultOpen={isDesktop} eventKey="6" className="customerReview" title={<h6>Customer Reviews</h6>}>
            <SitejabberBadge shouldFetchData />
          </Panel>
        </PanelGroup>
      </Panelstyled>
    );
  };

  const renderFooterTypeZero = () => {
    const { domain } = storedata;
    const isHomePage = currentUrl == '/' || router.asPath == '/new-home';
    const sameAs = [];

    sameAs.push(t('common:facebookSocial'));
    sameAs.push(t('common:twitterSocial'));

    if (storedata.storeId == 6) {
      sameAs.push(t('common:instagramSocial'));
      sameAs.push(t('common:youtubeSocial'));
      sameAs.push(t('common:pinterestSocial'));
    }

    if (storedata.storeId != 6) {
      if (storedata.storeId == 1) {
        sameAs.push(t('common:linkedinSocial'));
      }
      sameAs.push(t('common:youtubeSocial'));
      sameAs.push(t('common:pinterestSocial'));
      if (storedata.storeId != 5) {
        sameAs.push(t('common:instagramSocial'));
      }
    }

    const orgSchema = {
      '@context': 'https://schema.org',
      '@type': 'Organization',
      url: domain,
      sameAs: [...new Set(sameAs)].filter(Boolean),
      ...(isHomePage && {
        name: t('common:organisationName'),
        legalName: t('common:organisationLegalName'),
        logo: `${domain}/static/images/store/${storedata.storeId}/logo/logo.svg`,
        foundingDate: t('common:foundingDate'),
        founder: {
          '@type': 'Person',
          name: t('common:founderName'),
        },
        address: {
          '@type': 'PostalAddress',
          streetAddress: t('common:streetAddress'),
          addressLocality: t('common:addressLocality'),
          addressRegion: t('common:addressRegion'),
          postalCode: t('common:postalCode'),
          addressCountry: t('common:addressCountry'),
        },
        contactPoint: {
          '@type': 'ContactPoint',
          contactType: 'customer support',
          telephone: t('common:organisationTelphone'),
          email: t('common:organisationEmail'),
        },
      }),
    };

    return (
      <>
        <Head>
          <script
            type="application/ld+json"
            dangerouslySetInnerHTML={{
              __html: JSON.stringify(orgSchema),
            }}
          />
        </Head>
        <div className="Footerlinksstyled">
          <div className="container">
            {renderPenalGroup()}
            <div className="clearfix" />
            <hr />
            <div className="copyrightBox">
              <div className="stayConnectedBox">
                <h6>{'Add us on social media?'}</h6>
                <link href={domain} />

                {isHomePage && (
                  <div className="hide">
                    <span className="hide">{t('common:organisationName')}</span>
                    <span className="hide">{t('common:organisationLegalName')}</span>
                    <span className="hide">{`${domain}/static/images/store/${storedata.storeId}/logo/logo.svg`}</span>
                    <span className="hide">{t('common:foundingDate')}</span>
                    <span className="hide">

import React, { useEffect, useRef } from 'react';
import PropTypes from 'prop-types';
import dynamic from 'next/dynamic';
import { useSelector } from 'react-redux';
import { setEcommerceDataLayerPage } from '@/utils/common/ecommerceDataLayer';
import { setWebsiteTabSession, unSetWebsiteTabSession } from '@/utils/common/websiteTabSession';
import { setWebengageViewedProduct } from '@/utils/webEngage/setWebengageProductSearch';
import { setWebengagePageView } from '@/utils/webEngage/setWebEngageCommon';
import { checkIsLiteHouseOrGTmatrix } from '@/utils/deviceDetect';
import { checkIsPrivilegedUser } from '@/utils/commonFunction';
import RefferBanner from '../StayUpdate/RefferBanner';
import ThirdPartyJS from '../Footer/ThirdPartyJS';

const Stayupdate = dynamic(() => import('../StayUpdate/StayUpdate'));
const Footerlinks = dynamic(() => import('../FooterLinks/FooterLinks'));

const getFooterTypeClass = (footerType) => {
  switch (footerType) {
    case 0:
      return 'FooterTypeZiro';
    case 1:
      return 'FooterTypeOne';
    case 2:
      return 'FooterTypeTwo';
    case 4:
      return 'FooterTypeFour';
    case 5:
      return 'FooterTypeFive';
    case 6:
      return 'FooterTypeSix';
    default:
      return 'FooterTypeZiro';
  }
};

const Footer = ({ footerType, headertype, userAgent, router, loadThirdParty }) => {
  const { storedata, dataLayerPage, currentUrl, customerId } = useSelector(({ app, common, customer }) => ({
    storedata: app.storedata,
    dataLayerPage: common.dataLayerPage,
    currentUrl: common.currentUrl,
    customerId:
      customer.profile && customer.profile.customer_extra_fields && customer.profile.customer_extra_fields.id
        ? customer.profile.customer_extra_fields.id
        : null,
  }));

  const prevDataLayerPage = useRef(dataLayerPage);
  const prevCurrentUrl = useRef(currentUrl);
  const prevFooterType = useRef(footerType);

  useEffect(() => {
    if (process.env.NODE_ENV === 'production') {
      import('next-offline/runtime').then((runtime) => {
        runtime.register();
      });
    }

    if (typeof document !== 'undefined' && document.body) {
      if (navigator.userAgent.indexOf('Mac') > 0) document.body.className += ' mac-os';
      if (navigator.userAgent.indexOf('Safari') > 0) document.body.className += ' safari';
      if (navigator.userAgent.indexOf('Chrome') > 0) document.body.className += ' chrome';
      if (navigator.userAgent.indexOf('Edg') > 0) document.body.className += ' MS_edge';
      document.body.classList.add(getFooterTypeClass(footerType));
    }

    return () => {
      if (typeof window !== 'undefined' && window && typeof document !== 'undefined' && process.env.NODE_ENV === 'production') {
        import('next-offline/runtime').then((runtime) => {
          runtime.unregister();
        });
      }
      unSetWebsiteTabSession(customerId);
    };
    // mount/unmount parity with class lifecycle
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  useEffect(() => {
    if (prevDataLayerPage.current != dataLayerPage) {
      const recentlyViewed = (localStorage.getItem('rv_prods') && JSON.parse(localStorage.getItem('rv_prods'))) || [];
      setWebengageViewedProduct('Viewed Product', recentlyViewed);
      setEcommerceDataLayerPage(dataLayerPage);
      setWebengagePageView('DL_Pageview', dataLayerPage);
    }
    prevDataLayerPage.current = dataLayerPage;
  }, [dataLayerPage]);

  useEffect(() => {
    if (prevCurrentUrl.current != currentUrl) {
      setWebsiteTabSession(customerId);
    }
    prevCurrentUrl.current = currentUrl;
  }, [currentUrl, customerId]);

  useEffect(() => {
    if (prevFooterType.current != footerType && typeof document !== 'undefined' && document.body) {
      document.body.classList.remove(getFooterTypeClass(prevFooterType.current));
      document.body.classList.add(getFooterTypeClass(footerType));
    }
    prevFooterType.current = footerType;
  }, [footerType]);

  const { deviceType } = storedata;
  const isLighthouse = checkIsLiteHouseOrGTmatrix(userAgent);
  const isPrivilegedUser = checkIsPrivilegedUser(customerId || 0);

  return (
    <div
      className={`FooterMainBox ${router?.asPath === '/privilege' ? 'privilege-page' : ''}${deviceType === 2 ? 'ipadViewBox' : ''} ${
        deviceType === 1 ? 'mobileViewBox' : ''
      } ${isPrivilegedUser && deviceType === 2 ? 'privilageFooterbox' : ''}`}
    >
      <h1>Raj chavda&apos;s new footer</h1>
      {storedata?.storeId == 1 && footerType == 0 && <RefferBanner />}
      {footerType === 0 && router?.asPath !== '/privilege' && <Stayupdate currentUrl={currentUrl} />}
      <Footerlinks
        userAgent={userAgent}
        footerType={footerType}
        headertype={headertype}
        isLighthouse={isLighthouse}
        loadThirdParty={loadThirdParty}
        router={router}
      />
      <ThirdPartyJS isLighthouse={isLighthouse} loadThirdParty={loadThirdParty} />
    </div>
  );
};

Footer.propTypes = {
  footerType: PropTypes.number,
  headertype: PropTypes.any,
  userAgent: PropTypes.any,
  router: PropTypes.object,
  loadThirdParty: PropTypes.bool,
};

export default Footer;

