    if (prevProps.dataLayerPage != this.props.dataLayerPage) {
      setWebengageViewedProduct('Viewed Product', recentlyViewed);
      setEcommerceDataLayerPage(this.props.dataLayerPage);
      setWebengagePageView('DL_Pageview', this.props.dataLayerPage);
    }

    if (prevProps.currentUrl != this.props.currentUrl) {
      setWebsiteTabSession(customerId);
    }

    if (prevProps.footerType != this.props.footerType) {
      document.body.classList.remove(this.getFooterTypeClass(prevProps.footerType));
      document.body.classList.add(this.getFooterTypeClass(this.props.footerType));
    }
  }

  componentWillUnmount() {
    const { customerId } = this.props;
    if (typeof window !== 'undefined' && window && document && process.env.NODE_ENV === 'production') {
      import('next-offline/runtime').then((runtime) => {
        runtime.unregister();
      });
    }
    unSetWebsiteTabSession(customerId);
  }

  render() {
    const { footerType, storedata, userAgent, loadThirdParty } = this.props;
    const { deviceType } = storedata;
    const isLighthouse = checkIsLiteHouseOrGTmatrix(userAgent);
    const isPrivilegedUser = checkIsPrivilegedUser(this.props.customerId || 0);
    // eslint-disable-next-line no-console
    return (
      <div
        className={`FooterMainBox ${this.props?.router?.asPath === '/privilege' ? 'privilege-page' : ''}${deviceType === 2 ? 'ipadViewBox' : ''} ${
          deviceType === 1 ? 'mobileViewBox' : ''
        } ${isPrivilegedUser && deviceType === 2 ? 'privilageFooterbox' : ''}`}
      >
        {storedata?.storeId == 1 && footerType == 0 && <RefferBanner />}
        {footerType === 0 && this.props?.router?.asPath !== '/privilege' && <Stayupdate currentUrl={this.props.currentUrl} />}
        <Footerlinks
          userAgent={userAgent}
          footerType={footerType}
          headertype={this.props.headertype}
          isLighthouse={isLighthouse}
          loadThirdParty={loadThirdParty}
          router={this.props.router}
        />
        <ThirdPartyJS isLighthouse={isLighthouse} loadThirdParty={loadThirdParty} />
      </div>
    );
  }
}

